#!/usr/bin/env bash
set -e

cd "$(dirname "$0")/.."

echo "=== Kuayle - Seed Data ==="

# Ensure Docker CLI is in PATH (macOS Docker Desktop)
export PATH="/Applications/Docker.app/Contents/Resources/bin:$PATH"

# Load env
if [ -f .env ]; then
    set -a && source .env && set +a
fi

PSQL="docker compose exec -T postgres psql -U kuayle -d kuayle -q"

echo "Cleaning database..."
$PSQL <<'SQL'
-- Truncate all tables in dependency order
TRUNCATE TABLE
    favorites,
    issue_group_items,
    issue_groups,
    issue_assignees,
    team_statuses,
    issue_history,
    comments,
    issue_labels,
    issue_relations,
    issue_templates,
    notifications,
    refresh_tokens,
    views,
    webhooks,
    issues,
    cycles,
    labels,
    projects,
    project_members,
    team_members,
    workspace_members,
    teams,
    workspaces,
    users
CASCADE;
SQL
echo "Database cleaned."

echo "Generating seed data..."

# Generate bcrypt hash for "Password123!" using Go
cat > /tmp/hashgen.go <<'GOEOF'
package main
import (
    "fmt"
    "golang.org/x/crypto/bcrypt"
)
func main() {
    hash, _ := bcrypt.GenerateFromPassword([]byte("Password123!"), bcrypt.DefaultCost)
    fmt.Print(string(hash))
}
GOEOF
HASH=$(cd BE && go run /tmp/hashgen.go)
rm -f /tmp/hashgen.go

docker compose exec -T postgres psql -U kuayle -d kuayle -q -v "hash=$HASH" <<'SQL'

